member.example:
Bind a Renderer material color property using a serialized binder field — the target Renderer is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private RendererMaterialColorBinder _color;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Color _color;
    }


Bind a Renderer material color property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Renderer _renderer;
        
        private RendererMaterialColorBinder Color =>
            new(_renderer);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Color _color;
    }

Switch a Renderer material color between two values using a serialized binder field — the target Renderer is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private RendererMaterialColorSwitcherBinder _isHighlighted;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighlighted;
    }


Switch a Renderer material color between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private Renderer _renderer;
        
        [SerializeField]
        private Color _highlightedColor;
        
        [SerializeField]
        private Color _defaultColor;
        
        private RendererMaterialColorSwitcherBinder IsHighlighted => new(
            _renderer, _highlightedColor, _defaultColor);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighlighted;
    }
